const html = $input.first().json.html || "";

// -------------------------
// Helpers
// -------------------------

function match(regex) {
	const m = html.match(regex);
	return m ? m[1].trim() : "";
}

function count(regex) {
	return (html.match(regex) || []).length;
}

// -------------------------
// Basic SEO
// -------------------------

const title = match(/<title[^>]*>(.*?)<\/title>/is);

const description = match(
	/<meta[^>]*name=["']description["'][^>]*content=["']([^"]*)["']/i
);

const language = match(/<html[^>]*lang=["']([^"]+)["']/i);

const canonical = /rel=["']canonical["']/i.test(html);

const robots = /name=["']robots["']/i.test(html);

// -------------------------
// Headings
// -------------------------

const h1 = count(/<h1\b/gi);
const h2 = count(/<h2\b/gi);
const h3 = count(/<h3\b/gi);

// -------------------------
// Open Graph
// -------------------------

const ogTitle =
/property=["']og:title["']/i.test(html);

const ogDescription =
/property=["']og:description["']/i.test(html);

const ogImage =
/property=["']og:image["']/i.test(html);

// -------------------------
// Twitter
// -------------------------

const twitterCard =
/name=["']twitter:card["']/i.test(html);

const twitterTitle =
/name=["']twitter:title["']/i.test(html);

const twitterDescription =
/name=["']twitter:description["']/i.test(html);

// -------------------------
// Structured Data
// -------------------------

const schema =
/application\/ld\+json/i.test(html);

const organizationSchema =
/"@type"\s*:\s*"Organization"/i.test(html);

const localBusinessSchema =
/"@type"\s*:\s*"LocalBusiness"/i.test(html);

const faqSchema =
/"@type"\s*:\s*"FAQPage"/i.test(html);

const breadcrumbSchema =
/"@type"\s*:\s*"BreadcrumbList"/i.test(html);

// -------------------------
// Images
// -------------------------

const totalImages = count(/<img\b/gi);

const imagesWithAlt = count(
/<img[^>]*alt=["'][^"']*["']/gi
);

const imagesMissingAlt =
Math.max(totalImages - imagesWithAlt,0);

// -------------------------
// Crawlability
// -------------------------

const favicon =
/rel=["']icon["']/i.test(html) ||
/rel=["']shortcut icon["']/i.test(html);

// -------------------------
// Score
// -------------------------

let score = 100;

const strengths = [];
const opportunities = [];

// Title

if(!title){
score -= 10;
opportunities.push("Missing title tag");
}else{

if(title.length < 30){
score -= 4;
opportunities.push("Title too short");
}

if(title.length > 60){
score -= 4;
opportunities.push("Title too long");
}else{
strengths.push("Optimized page title");
}

}

// Description

if(!description){
score -= 10;
opportunities.push("Missing meta description");
}else{

if(description.length < 120){
score -= 3;
opportunities.push("Meta description too short");
}

if(description.length > 160){
score -= 3;
opportunities.push("Meta description too long");
}

}

// H1

if(h1===0){
score -= 10;
opportunities.push("Missing H1");
}

if(h1===1){
strengths.push("Single H1 detected");
}

if(h1>1){
score -= 5;
opportunities.push("Multiple H1 headings");
}

// Language

if(language){
strengths.push("Language attribute present");
}else{
score -= 3;
opportunities.push("Missing language attribute");
}

// Canonical

if(canonical){
strengths.push("Canonical URL present");
}else{
score -= 5;
opportunities.push("Missing canonical URL");
}

// Robots

if(robots){
strengths.push("Robots meta configured");
}else{
score -= 3;
opportunities.push("Missing robots meta");
}

// Open Graph

if(ogTitle && ogDescription && ogImage){
strengths.push("Open Graph configured");
}else{
score -= 3;
opportunities.push("Incomplete Open Graph tags");
}

// Twitter

if(twitterCard){
strengths.push("Twitter Card detected");
}else{
score -= 2;
opportunities.push("Missing Twitter Card");
}

// Schema

if(schema){
strengths.push("Structured data detected");
}else{
score -= 5;
opportunities.push("No structured data detected");
}

// Image Alt

if(totalImages>0){

if(imagesMissingAlt===0){

strengths.push("All images include alt text");

}else{

score -= Math.min(imagesMissingAlt,5);

opportunities.push(
`${imagesMissingAlt} image(s) missing alt text`
);

}

}

// Favicon

if(favicon){
strengths.push("Favicon detected");
}else{
score -= 2;
opportunities.push("Missing favicon");
}

score = Math.max(0,Math.round(score));

// -------------------------
// Output
// -------------------------

return [{
json:{

seo:{

score,

metrics:{

titleLength:title.length,

descriptionLength:description.length,

language,

h1,

h2,

h3,

canonical,

robots,

openGraph:{
title:ogTitle,
description:ogDescription,
image:ogImage
},

twitter:{
card:twitterCard,
title:twitterTitle,
description:twitterDescription
},

schema:{
present:schema,
organization:organizationSchema,
localBusiness:localBusinessSchema,
faq:faqSchema,
breadcrumb:breadcrumbSchema
},

images:{
total:totalImages,
withAlt:imagesWithAlt,
missingAlt:imagesMissingAlt
},

favicon

},

title,

description,

strengths,

opportunities

}

}
}];

