const audit = $input.first().json;

const scores = [
  audit.seo?.score,
  audit.ux?.score,
  audit.conversion?.score,
  audit.tech?.score,
].filter(score => typeof score === "number");

if (scores.length === 0) {
  throw new Error("No audit scores found.");
}

const overall = Math.round(
  scores.reduce((a, b) => a + b, 0) / scores.length
);

let grade = "";
let status = "";

if (overall >= 95) {
  grade = "A+";
  status = "Excellent";
} else if (overall >= 90) {
  grade = "A";
  status = "Outstanding";
} else if (overall >= 80) {
  grade = "B";
  status = "Good";
} else if (overall >= 70) {
  grade = "C";
  status = "Needs Improvement";
} else if (overall >= 60) {
  grade = "D";
  status = "Poor";
} else {
  grade = "F";
  status = "Critical";
}

const issueCount = audit.opportunities?.length || 0;

let estimatedScore = Math.min(
  100,
  Math.round(overall + issueCount * 1.5)
);

return [{
  json: {
    ...audit,
    overall,
    grade,
    status,
    estimatedScore,
    improvementPotential: estimatedScore - overall
  }
}];

