const audit = $input.first().json;

// ----------------------
// Weight every strength
// ----------------------

const weights = {

SEO:5,
Performance:5,
Accessibility:5,
Security:5,
Conversion:4,
Branding:4,
Content:4,
Trust:4,
UX:3,
Tech:3

};

// ----------------------
// Build master strength list
// ----------------------

const strengths = [];

[
"seo",
"ux",
"conversion",
"tech",
"branding",
"content",
"performance",
"accessibility",
"security",
"trust"

].forEach(section=>{

    if(!audit[section]) return;

    (audit[section].strengths || []).forEach(item=>{

        strengths.push({

            section,

            strength:item,

            score:weights[
                section.charAt(0).toUpperCase() +
                section.slice(1)
            ] || 1

        });

    });

});

// ----------------------
// Merge duplicates
// ----------------------

const unique = [];

const seen = new Set();

strengths.forEach(s=>{

    const key = s.strength.toLowerCase();

    if(!seen.has(key)){

        seen.add(key);

        unique.push(s);

    }

});

// ----------------------
// Sort by importance
// ----------------------

unique.sort((a,b)=>b.score-a.score);

// ----------------------
// Keep only the best
// ----------------------

const topStrengths = unique.slice(0,5);

// ----------------------
// Summary
// ----------------------

const strengthSummary = {

total:unique.length,

top:topStrengths

};

// ----------------------
// Return
// ----------------------

return [{

json:{

...audit,

strengthSummary,

topStrengths

}

}];

const audit = $input.first().json;

const impactWeight = {
    High: 3,
    Medium: 2,
    Low: 1
};

const effortWeight = {
    Easy: 3,
    Medium: 2,
    Hard: 1,
    Unknown: 1
};

const opportunities = (audit.recommendations || []).map(rec => {

    const impact = impactWeight[rec.impact] || 1;
    const effort = effortWeight[rec.effort] || 1;
    const gain = rec.expectedGain || 1;

    // ROI score
    const score = (impact * 3) + gain + effort;

    return {
        ...rec,
        roiScore: score
    };

});

// Remove duplicates
const seen = new Set();

const unique = opportunities.filter(item => {

    if(seen.has(item.issue)) return false;

    seen.add(item.issue);

    return true;

});

// Highest ROI first
unique.sort((a,b)=>b.roiScore-a.roiScore);

// Top fixes
const top5 = unique.slice(0,5);

// Medium priority
const medium = unique.slice(5,10);

// Remaining
const backlog = unique.slice(10);

return [{

json:{

...audit,

roadmap:{

topPriority:top5,

mediumPriority:medium,

backlog

}

}

}];

const audit = $input.first().json;

const seen = new Set();

const recommendations = [];

(audit.recommendations || []).forEach(rec => {

    const key = rec.issue.toLowerCase();

    if (!seen.has(key)) {

        seen.add(key);

        recommendations.push(rec);

    }

});

const summary = {
    before: audit.recommendations?.length || 0,
    after: recommendations.length,
    removed: (audit.recommendations?.length || 0) - recommendations.length
};

return [{
    json: {
        ...audit,
        recommendations,
        recommendationSummary: {
            ...(audit.recommendationSummary || {}),
            total: recommendations.length
        },
        deduplication: summary
    }
}];

const audit = $input.first().json;

const current = audit.overall || 0;

const roadmap = audit.roadmap90 || {};

const immediate = roadmap.immediate?.scoreGain || 0;
const shortTerm = roadmap.shortTerm?.scoreGain || 0;
const longTerm = roadmap.longTerm?.scoreGain || 0;

function projected(score, gain){

    // diminishing returns

    return Math.min(
        100,
        Math.round(score + (gain * (100-score)/100))
    );

}

const projections = {

    current,

    afterImmediate:
        projected(current, immediate),

    afterShortTerm:
        projected(
            projected(current, immediate),
            shortTerm
        ),

    afterLongTerm:
        projected(
            projected(
                projected(current, immediate),
                shortTerm
            ),
            longTerm
        )

};

return [{

json:{

...audit,

scoreProjection: projections

}

}];

